export async function loadAndSetLocale(nuxtApp: NuxtApp, locale: Locale): Promise<string> {
  const ctx = useNuxtI18nContext(nuxtApp)
  const oldLocale = ctx.getLocale()

  // skip if locale is already set and there is no pending locale change to a different locale
  if (locale === oldLocale && !ctx.initial && (!ctx.vueI18n.__pendingLocale || ctx.vueI18n.__pendingLocale === locale)) {
    return locale
  }

  const data = { oldLocale, newLocale: locale, initialSetup: ctx.initial, context: nuxtApp }
  let override = (await nuxtApp.callHook('i18n:beforeLocaleSwitch', data)) as string | undefined
  if (override != null && import.meta.dev) {
    console.warn('[nuxt-i18n] Do not return in `i18n:beforeLocaleSwitch`, mutate `data.newLocale` instead.')
  }
  override ??= data.newLocale

  if (isSupportedLocale(override)) {
    locale = override
  }

  await ctx.loadMessages(locale)
  await ctx.setLocaleSuspend(locale)

  return locale
}

export function detectLocale(nuxtApp: NuxtApp, route: string | CompatRoute): string {
  const detectConfig = useI18nDetection(nuxtApp)
  const detectors = useDetectors(useRequestEvent(nuxtApp), detectConfig, nuxtApp)
  const ctx = useNuxtI18nContext(nuxtApp)
  const path = isString(route) ? route : route.path

  function* detect() {
    if (ctx.initial && detectConfig.enabled && !skipDetect(detectConfig, path, detectors.route(path))) {
      yield detectors.cookie()
      yield detectors.header()
      yield detectors.navigator()
      yield detectConfig.fallbackLocale
    }

    if (__DIFFERENT_DOMAINS__ || __MULTI_DOMAIN_LOCALES__) {
      yield detectors.host(path)
    }

    if (__I18N_ROUTING__) {
      yield detectors.route(route)
    }
  }

  for (const detected of detect()) {
    if (detected && isSupportedLocale(detected)) {
      return detected
    }
  }

  return ctx.getLocale() || ctx.getDefaultLocale() || ''
}

export function navigate(nuxtApp: NuxtApp, to: CompatRoute, locale: string) {
  if (!__I18N_ROUTING__ || __DIFFERENT_DOMAINS__) { return }

  const ctx = useNuxtI18nContext(nuxtApp)
  const _ctx = useComposableContext(nuxtApp)

  if (to.path === '/' && ctx.rootRedirect) {
    return navigateTo(localePath(_ctx, ctx.rootRedirect.path, locale), { redirectCode: ctx.rootRedirect.code })
  }

  // skip - pending locale inside navigation middleware
  if (ctx.vueI18n.__pendingLocale && useNuxtApp()._processingMiddleware) {
    return
  }

  // skip - redirection optional prevents prefix removal, reconsider if needed (#2288)
  const detectors = useDetectors(useRequestEvent(), useI18nDetection(nuxtApp), nuxtApp)
  if (detectors.route(to) === locale) {
    return
  }

  // skip redirect if resolved route matches current route (#1889, #2226)
  const destination = switchLocalePath(_ctx, locale, to) || localePath(_ctx, to.fullPath, locale)
  if (isEqual(destination, to.fullPath)) {
    return
  }

  return navigateTo(destination, { redirectCode: ctx.redirectStatusCode })
}

export function useState<T> (key?: string, init?: (() => T | Ref<T>)): Ref<T>
export function useState<T> (init?: (() => T | Ref<T>)): Ref<T>
export function useState<T> (...args: any): Ref<T> {
  const autoKey = typeof args[args.length - 1] === 'string' ? args.pop() : undefined
  if (typeof args[0] !== 'string') { args.unshift(autoKey) }
  const [_key, init] = args as [string, (() => T | Ref<T>)]
  if (!_key || typeof _key !== 'string') {
    throw new TypeError('[nuxt] [useState] key must be a string: ' + _key)
  }
  if (init !== undefined && typeof init !== 'function') {
    throw new Error('[nuxt] [useState] init must be a function: ' + init)
  }
  const key = useStateKeyPrefix + _key

  const nuxtApp = useNuxtApp()
  const state = toRef(nuxtApp.payload.state, key)

  // Register the init function for reset support
  if (init) {
    nuxtApp._state[key] ??= { _default: init }
  }

  if (state.value === undefined && init) {
    const initialValue = init()
    if (isRef(initialValue)) {
      // vue will unwrap the ref for us
      nuxtApp.payload.state[key] = initialValue
      return initialValue as Ref<T>
    }
    state.value = initialValue
  }
  return state
}

export const getMergedMessages = cachedFunctionI18n(_getMergedMessages, {
  name: 'merged-single',
  maxAge: !__I18N_CACHE__ ? -1 : 60 * 60 * 24,
  getKey: (locale, fallbackLocales) => `${locale}-[${[...new Set(fallbackLocales)].sort().join('-')}]`,
  shouldBypassCache: (locale, fallbackLocales) => !isLocaleWithFallbacksCacheable(locale, fallbackLocales),
})

const _getAllMergedMessages = async (locales: string[]) => {
  const merged = {} as LocaleMessages<DefineLocaleMessage>

  try {
    const messages = await Promise.all(locales.map(getMessages))

    for (const message of messages) {
      deepCopy(message, merged)
    }

    return merged
  } catch (e) {
    throw new Error('Failed to merge messages: ' + (e as Error).message)
  }
}

export const getAllMergedMessages = cachedFunctionI18n(_getAllMergedMessages, {
  name: 'merged-all',
  maxAge: !__I18N_CACHE__ ? -1 : 60 * 60 * 24,
  getKey: locales => locales.join('-'),
  shouldBypassCache: locales => !locales.every(locale => isLocaleCacheable(locale)),
})

async run(ctx) {
  process.env.NODE_ENV = process.env.NODE_ENV || 'production'

  const cwd = resolve(ctx.args.cwd || ctx.args.rootDir)

  const [supportsProjects, vueTsc] = await Promise.all([
    readTSConfig(cwd).then(r => !!(r.references?.length)),
    ensureVueTsc(cwd, resolveDeps()),
    writeTypes(cwd, ctx.args.dotenv, ctx.args.logLevel as 'silent' | 'info' | 'verbose', {
      ...ctx.data?.overrides,
      ...(ctx.args.extends && { extends: ctx.args.extends }),
    }),
  ])

  if (!vueTsc) {
    process.exitCode = 1
    return
  }

  const start = Date.now()
  const result = await x(vueTsc, supportsProjects ? ['-b', '--noEmit'] : ['--noEmit'], {
    nodeOptions: { stdio: 'inherit', cwd },
  })
  const duration = `${Date.now() - start}ms`

  if (result.exitCode === 0) {
    if (hasTTY) {
      logger.success(`Type check passed in ${colors.cyan(duration)}.`)
    }
    return
  }

  if (hasTTY) {
    logger.error(`Type check failed in ${colors.cyan(duration)}.`)
  }
  process.exitCode = result.exitCode ?? 1
}

private createFork(): PooledFork {
  const childProc = fork(globalThis.__nuxt_cli__.devEntry!, this.rawArgs, {
    execArgv: ['--enable-source-maps', process.argv.find((a: string) => a.includes('--inspect'))].filter(Boolean) as string[],
    env: {
      ...process.env,
      __NUXT__FORK: 'true',
    },
  })

  let readyResolve: () => void
  let readyReject: (err: Error) => void
  const ready = new Promise<void>((resolve, reject) => {
    readyResolve = resolve
    readyReject = reject
  })

  const pooledFork: PooledFork = {
    process: childProc,
    ready,
    state: 'warming',
  }

  // Listen for fork-ready message
  childProc.on('message', (message: NuxtDevIPCMessage) => {
    if (message.type === 'nuxt:internal:dev:fork-ready') {
      readyResolve()
    }
  })

  // Handle errors
  childProc.on('error', (err) => {
    readyReject(err)
    this.removeFork(pooledFork)
  })

  // Handle unexpected exit
  childProc.on('close', (errorCode) => {
    if (pooledFork.state === 'active' && errorCode) {
      // Active fork crashed
      process.exit(errorCode)
    }
    this.removeFork(pooledFork)
  })

  return pooledFork
}

function refineDatabaseConfig(config: RuntimeConfig['content']['database']) {
  if (config.type === 'd1') {
    return { ...config, bindingName: config.bindingName || config.binding }
  }

  if (config.type === 'sqlite') {
    const _config = { ...config } as SqliteConnectorOptions
    if (config.filename === ':memory:') {
      return { name: ':memory:' }
    }

    if ('filename' in config) {
      const filename = isAbsolute(config?.filename || '') || config?.filename === ':memory:'
        ? config?.filename
        : new URL(config.filename, (globalThis as unknown as { _importMeta_: { url: string } })._importMeta_.url).pathname

      _config.path = process.platform === 'win32' && filename.startsWith('/') ? filename.slice(1) : filename
    }
    return _config
  }

  if (config.type === 'pglite') {
    // PGlite uses dataDir for storage location
    // If no dataDir is provided, it will use in-memory storage
    return {
      dataDir: config.dataDir,
      // Pass through any other PGlite-specific options
      ...config,
    }
  }

  return config
}

export function createAddonGlobals(nuxt: Nuxt): ESLintConfigGenAddon {
  let unimport: Unimport | undefined
  let nitroUnimport: Unimport | undefined

  nuxt.hook('imports:context', (context) => {
    unimport = context
  })

  nuxt.hook('nitro:init', (nitro: Nitro) => {
    nitroUnimport = nitro.unimport
  })

  return {
    name: 'nuxt:eslint:import-globals',
    async getConfigs() {
      const imports = [
        ...await unimport?.getImports() || [],
        ...await nitroUnimport?.getImports() || [],
      ].sort((a, b) => 10 * a.from.localeCompare(b.from) + a.name.localeCompare(b.name))

      return {
        configs: [
          [
            '// Set globals from imports registry',
            '{',
            `  name: 'nuxt/import-globals',`,
            '  languageOptions: {',
            `    globals: Object.fromEntries(${JSON.stringify(imports.map(i => i.as || i.name))}.map(i => [i, 'readonly'])),`,
            `  },`,
            '}',
          ].join('\n'),
        ],
      }
    },
  }
}

export async function setupConfigGen(options: ModuleOptions, nuxt: Nuxt) {
  const {
    autoInit = true,
  } = typeof options.config !== 'boolean' ? options.config || {} : {}

  const defaultAddons = [
    createAddonGlobals(nuxt),
  ]

  nuxt.hook('prepare:types', ({ declarations, nodeReferences }) => {
    declarations.push('/// <reference path="./eslint-typegen.d.ts" />')
    if (nodeReferences)
      nodeReferences.push({ path: join(nuxt.options.buildDir, 'eslint-typegen.d.ts') })
  })

  let _configFile: string = undefined!

  async function writeConfigFile() {
    const addons: ESLintConfigGenAddon[] = [
      ...defaultAddons,
    ]
    await nuxt.callHook('eslint:config:addons', addons)
    const { code, codeDts, configFile } = await generateESLintConfig(options, nuxt, addons)
    await fs.mkdir(dirname(configFile), { recursive: true })
    await fs.writeFile(configFile, code, 'utf-8')
    await fs.writeFile(configFile.replace(/\.mjs$/, '.d.mts'), codeDts, 'utf-8')
    _configFile = configFile
  }

  setupDevToolsIntegration(options, nuxt)

  await writeConfigFile()
  nuxt.hook('builder:generateApp', async () => {
    await writeConfigFile()
  })

  if (autoInit) {
    await initRootESLintConfig(nuxt, _configFile)
  }
}

export function normalizeTemplate<T> (template: NuxtTemplate<T> | string, buildDir?: string): ResolvedNuxtTemplate<T> {
  if (!template) {
    throw new Error('Invalid template: ' + JSON.stringify(template))
  }

  // Normalize
  if (typeof template === 'string') {
    template = { src: template }
  } else {
    template = { ...template }
  }

  // Use src if provided
  if (template.src) {
    if (!existsSync(template.src)) {
      throw new Error('Template not found: ' + template.src)
    }
    if (!template.filename) {
      const srcPath = parse(template.src)
      template.filename = (template as any).fileName || `${basename(srcPath.dir)}.${srcPath.name}.${hash(template.src).replace(/-/g, '_')}${srcPath.ext}`
    }
  }

  if (!template.src && !template.getContents) {
    throw new Error('Invalid template. Either `getContents` or `src` should be provided: ' + JSON.stringify(template))
  }

  if (!template.filename) {
    throw new Error('Invalid template. `filename` must be provided: ' + JSON.stringify(template))
  }

  // Always write declaration files
  if (template.filename.endsWith('.d.ts')) {
    template.write = true
  }

  // Resolve dst
  template.dst ||= resolve(buildDir ?? useNuxt().options.buildDir, template.filename)

  return template as ResolvedNuxtTemplate<T>
}

export default defineProvider<StoryblokOptions>({
  getImage: (src, { modifiers, baseURL = storyblockCDN }) => {
    const {
      fit,
      smart,
      width = '0',
      height = '0',
      filters = {},
      format,
      quality,
    } = modifiers

    const isSVG = src.endsWith('.svg')
    const doResize = !isSVG && (width !== '0' || height !== '0')

    if (!isSVG) {
      if (format) {
        filters.format = format + ''
      }

      if (quality) {
        filters.quality = quality + ''
      }
    }

    const _filters = Object.entries(filters || {}).map(e => `${e[0]}(${e[1]})`).join(':')

    const options = joinURL(
      fit ? `fit-${fit}` : '',
      doResize ? `${width}x${height}` : '',
      smart ? 'smart' : '',
      _filters ? ('filters:' + _filters) : '',
    )

    const { pathname } = parseURL(src)

    const modifier = options ? '/m/' : ''

    const url = withBase(joinURL(pathname, modifier, options), baseURL)

    return {
      url,
    }
  },
})

function getResizeValue(height?: number, width?: number) {
  if (width && height) {
    return { fw: width, fh: height }
  }
  else if (width) {
    return { w: width }
  }
  else if (height) {
    return { h: height }
  }
}

export default defineProvider<AliyunOptions>({
  getImage: (src, { modifiers, baseURL }) => {
    if (!baseURL) {
      // also support runtime config
      baseURL = useRuntimeConfig().public.siteUrl as string | undefined || '/'
    }
    const _modifiers = { ...modifiers }
    const { resize, width, height, quality } = _modifiers

    const resizeValue = getResizeValue(height, width)
    if (!resize && resizeValue) {
      _modifiers.resize = resizeValue
    }
    delete _modifiers.width
    delete _modifiers.height

    if (quality) {
      _modifiers.quality = `Q_${quality}`
    }

    const operations = operationsGenerator(_modifiers)
    return {
      url: joinURL(baseURL, src + (operations ? '?image_process=' + operations : '')),
    }
  },
})

({
  opts,
  orientation,
  plugins,
}: CarouselProps, emits: CarouselEmits) => {
  const [emblaNode, emblaApi] = emblaCarouselVue({
    ...opts,
    axis: orientation === 'horizontal' ? 'x' : 'y',
  }, plugins)

  function scrollPrev() {
    emblaApi.value?.scrollPrev()
  }
  function scrollNext() {
    emblaApi.value?.scrollNext()
  }

  const canScrollNext = ref(false)
  const canScrollPrev = ref(false)

  function onSelect(api: CarouselApi) {
    canScrollNext.value = api?.canScrollNext() || false
    canScrollPrev.value = api?.canScrollPrev() || false
  }

  onMounted(() => {
    if (!emblaApi.value)
      return

    emblaApi.value?.on('init', onSelect)
    emblaApi.value?.on('reInit', onSelect)
    emblaApi.value?.on('select', onSelect)

    emits('init-api', emblaApi.value)
  })

  return { carouselRef: emblaNode, carouselApi: emblaApi, canScrollPrev, canScrollNext, scrollPrev, scrollNext, orientation }
}

export async function resolveEvlogConfigForNitroPlugin(): Promise<EvlogConfig | undefined> {
  const fromInline = readEvlogConfigFromInline()
  if (fromInline !== undefined) return fromInline

  const fromEnv = readEvlogConfigFromNitroEnv()
  if (fromEnv !== undefined) return fromEnv

  if (activeNitroRuntime === 'v3') {
    const v3 = await getNitroV3Runtime()
    if (v3) {
      const slice = evlogSlice(v3.useRuntimeConfig())
      if (slice !== undefined) return slice
    }
    return undefined
  }

  if (activeNitroRuntime === 'v2') {
    const internal = await getNitropackInternalRuntimeConfig()
    if (internal) {
      const slice = evlogSlice(internal.useRuntimeConfig())
      if (slice !== undefined) return slice
    }
    return undefined
  }

  const v3 = await getNitroV3Runtime()
  if (v3) {
    const slice = evlogSlice(v3.useRuntimeConfig())
    if (slice !== undefined) return slice
  }

  const internal = await getNitropackInternalRuntimeConfig()
  if (internal) {
    const slice = evlogSlice(internal.useRuntimeConfig())
    if (slice !== undefined) return slice
  }

  return undefined
}

async onInstall(nuxt) {
  const shouldSetup = await consola.prompt(
    'Do you want to create a vercel.json with a cron schedule for evlog cleanup?',
    { type: 'confirm', initial: false },
  )
  if (typeof shouldSetup !== 'boolean' || !shouldSetup) return

  const vercelJsonPath = resolve(nuxt.options.rootDir, 'vercel.json')
  let config: VercelConfig = {}
  if (existsSync(vercelJsonPath)) {
    config = JSON.parse(await fsp.readFile(vercelJsonPath, 'utf-8')) as VercelConfig
  }

  const evlogConfig = getNuxtEvlogConfig(nuxt)
  const retention = evlogConfig.retention ?? '7d'
  const cron = retentionToCron(retention)

  const crons: Array<{ path: string, schedule: string }> = Array.isArray(config.crons) ? config.crons : []
  const existing = crons.findIndex(c => c.path === '/api/_cron/evlog-cleanup')
  if (existing >= 0) {
    const entry = crons[existing]
    if (entry) entry.schedule = cron
  } else {
    crons.push({ path: '/api/_cron/evlog-cleanup', schedule: cron })
  }
  config.crons = crons

  await fsp.writeFile(vercelJsonPath, `${JSON.stringify(config, null, 2)}\n`, 'utf-8')
  consola.success('Created vercel.json with evlog cleanup cron schedule')
}

async function renameAsset() {
  const parts = asset.value.filePath.split('/')
  const oldName = parts.slice(-1)[0]?.split('.').slice(0, -1).join('.')

  if (!newName.value || newName.value === oldName) {
    return devtoolsUiShowNotification({
      message: 'Please enter a new name',
      icon: 'i-carbon-warning',
      classes: 'text-orange',
    })
  }

  try {
    const extension = parts.slice(-1)[0]?.split('.').slice(-1)[0]
    const fullPath = `${parts.slice(0, -1).join('/')}/${newName.value}.${extension}`
    await rpc.renameStaticAsset(asset.value.filePath, fullPath)
    asset.value = undefined as any
    renameDialog.value = false
    devtoolsUiShowNotification({
      message: 'Asset renamed',
      icon: 'i-carbon-checkmark',
      classes: 'text-green',
    })
  }
  catch (error) {
    console.error(error)
    devtoolsUiShowNotification({
      message: 'Something went wrong!',
      icon: 'i-carbon-warning',
      classes: 'text-red',
    })
  }
}

async function uploadFiles() {
  if (wsConnecting.value || wsError.value)
    return

  telemetry('assets:upload')

  const uploadFiles: AssetEntry[] = []
  for (const file of files.value) {
    const reader = new FileReader()
    reader.readAsDataURL(file)
    const result = await new Promise((resolve) => {
      reader.onload = () => resolve(reader.result as string)
    }) as string
    // TODO: add validation
    const content = result.split(';base64,').pop() as string
    uploadFiles.push({
      path: file.name,
      encoding: 'base64',
      content,
    })
  }
  await rpc.writeStaticAssets([...uploadFiles], props.folder).then(() => {
    close()
    devtoolsUiShowNotification({
      message: 'Files uploaded successfully!',
      icon: 'i-carbon:checkmark',
    })
  }).catch((error) => {
    close()
    devtoolsUiShowNotification({
      message: `Error uploading files: ${error?.message ?? 'unknown'}`,
      icon: 'i-carbon-warning',
      classes: 'text-red',
    })
  })
  visible.value = false
}

() => {
  const view = props.tab.view as ModuleIframeView
  const isPersistent = view.persistent !== false
  const allowedPermissions = ['clipboard-write', 'clipboard-read', ...(view.permissions || [])]

  if (iframeCacheMap.get(key.value) && isPersistent) {
    iframeEl.value = iframeCacheMap.get(key.value)!
    iframeEl.value.style.visibility = 'visible'
  }
  else {
    iframeEl.value = document.createElement('iframe')
    iframeEl.value.setAttribute('allow', allowedPermissions.join('; '))
    iframeEl.value.setAttribute('aria-label', 'Nuxt Devtools')

    if (isPersistent)
      iframeCacheMap.set(key.value, iframeEl.value)
    iframeEl.value.src = view.src
    // CORS
    try {
      iframeEl.value.style.opacity = '0.01'
      iframeEl.value.onload = () => {
        injectClient()
        syncColorMode()
        iframeEl.value!.style.opacity = '1'
      }
    }
    catch (e) {
      iframeEl.value.style.opacity = '1'
    }
    document.body.appendChild(iframeEl.value)
    nextTick(updateIframeBox)
  }
  setTimeout(syncColorMode, 100)
}

() => {
  const snippets: CodeSnippet[] = []

  const items: string[] = []
  const headers = Object.entries(parsedHeader.value)
    .filter(([key, value]) => key && value && !(key === 'Content-Type' && value === 'application/json'))
    .map(([key, value]) => `  '${key}': '${value}'`)
    .join(',\n')

  if (routeMethod.value.toUpperCase() !== 'GET')
    items.push(`method: '${routeMethod.value.toUpperCase()}'`)
  if (headers)
    items.push(`headers: {\n${headers}\n}`)
  if (parsedBody.value)
    items.push(`body: ${JSON.stringify(parsedBody.value, null, 2)}`)

  const options = items.length
    ? `, {
${items.join(',\n').split('\n').map(line => `  ${line}`).join('\n')}
}`
    : ''

  snippets.push({
    name: 'useFetch',
    lang: 'javascript',
