  })

  return snippets
}

function wrapTranslationFunctions(ctx: NuxtI18nContext, serverI18n = useRequestEvent()?.context?.nuxtI18n) {
  if (!serverI18n) { return }

  const i18n = ctx.vueI18n.global
  const originalT = i18n.t.bind(i18n)
  type TParams = Parameters<typeof originalT>
  i18n.t = (
    key: string,
    listOrNamed?: string | number | unknown[] | Record<string, unknown>,
    opts?: TranslateOptions<string> | number | string,
  ) => {
    const locale = ((typeof opts === 'object' && opts?.locale) || ctx.getLocale()) as string
    serverI18n?.trackKey(key, locale)
    // @ts-expect-error type mismatch

    return originalT(key, listOrNamed as TParams[1], opts)
  }

  const originalTe = i18n.te.bind(i18n)
  i18n.te = (key, locale) => {
    serverI18n?.trackKey(key, locale || ctx.getLocale())
    return originalTe(key, locale)
  }

  const originalTm = i18n.tm.bind(i18n)
  i18n.tm = (key) => {
    serverI18n?.trackKey(key, ctx.getLocale())
    return originalTm(key)
  }
}

export async function extractLinks(html: string, from: string, res: Response, crawlLinks: boolean) {
  const links: string[] = [];
  const _links: string[] = [];

  // Extract from any <TAG href=""> to crawl
  if (crawlLinks) {
    await walk(parseHTML(html), (node) => {
      if (!node.attributes?.href) {
        return;
      }

      const link = escapeHtml(node.attributes.href);
      if (!decodeURIComponent(link).startsWith("#") && allowedExtensions.has(getExtension(link))) {
        _links.push(link);
      }
    });
  }

  // Extract from x-nitro-prerender headers
  const header = res.headers.get("x-nitro-prerender") || "";
  _links.push(...header.split(",").map((i) => decodeURIComponent(i.trim())));

  for (const link of _links.filter(Boolean)) {
    const _link = parseURL(link);
    if (_link.protocol || _link.host) {
      continue;
    }
    if (!_link.pathname.startsWith("/")) {
      const fromURL = new URL(from, "http://localhost");
      _link.pathname = new URL(_link.pathname, fromURL).pathname;
    }
    links.push(_link.pathname + _link.search);
  }
  for (const link of links) {
    const _parents = linkParents.get(link);
    if (_parents) {
      _parents.add(from);
    } else {
      linkParents.set(link, new Set([from]));
    }
  }
  return links;
}

function getIframe() {
  if (!iframe) {
    const runtimeConfig = useRuntimeConfig()
    const CLIENT_BASE = '/__nuxt_devtools__/client'
    const CLIENT_PATH = `${runtimeConfig.app.baseURL.replace(CLIENT_BASE, '/')}${CLIENT_BASE}`.replace(MULTIPLE_SLASHES_RE, '/')
    const initialUrl = CLIENT_PATH + state.value.route
    iframe = document.createElement('iframe')

    // custom iframe props
    for (const [key, value] of Object.entries(runtimeConfig.app.devtools?.iframeProps || {}))
      iframe.setAttribute(key, String(value))

    iframe.id = 'nuxt-devtools-iframe'
    iframe.src = initialUrl
    iframe.onload = async () => {
      try {
        setIframeServerContext(iframe!)
        await waitForClientInjection()
        client.syncClient()
      }
      catch (e) {
        console.error('Nuxt DevTools client injection failed')
        console.error(e)
      }
    }
  }

  return iframe
}

export function cachedFunctionI18n<T, ArgsT extends unknown[] = any[]>(
  fn: (...args: ArgsT) => T | Promise<T>,
  opts: CacheOptions<ArgsT>,
): (...args: ArgsT) => Promise<T | undefined> {
  opts = { maxAge: 1, ...opts }
  const pending: { [key: string]: Promise<T> } = {}

  async function get(key: string, resolver: () => T | Promise<T>) {
    const isPending = pending[key]

    if (!isPending) {
      pending[key] = Promise.resolve(resolver())
    }

    try {
      return await pending[key]
    } finally {
      // Ensure we always clean up, whether the promise resolved or rejected.
      delete pending[key]
    }
  }

  return async (...args) => {
    const key = [opts.name, opts.getKey(...args)].join(':').replace(/:\/$/, ':index')
    const maxAge = opts.maxAge ?? 1
    const isCacheable = !opts.shouldBypassCache(...args) && maxAge >= 0

    const cache = isCacheable && (await storage.getItemRaw<CachedValue<T>>(key))
    if (!cache || cache.ttl < Date.now()) {
      pending[key] = Promise.resolve(fn(...args))
      const value = await get(key, () => fn(...args))

      if (isCacheable) {
        await storage.setItemRaw(key, { ttl: Date.now() + maxAge * 1000, value, mtime: Date.now() })
      }

      return value
    }

    return cache.value
  }
}

function setFiles(data: FileList | null) {
  const inputFiles = [...data || []]
  if (inputFiles.length) {
    const newFiles: File[] = []
    const existingFileNames: string[] = files.value.map(file => file.name)
    for (const file of inputFiles) {
      if (existingFileNames.includes(file.name)) {
        let i = 1
        const [name, ext] = file.name.split('.')
        while (existingFileNames.includes(`${name} (${i}).${ext}`))
          i++
        const newFilename = `${name}-${i}.${ext}`
        const blob = new Blob([file], { type: file.type })
        const newFile = new File([blob], newFilename, { lastModified: Date.now() })
        newFiles.push(newFile)
        existingFileNames.push(newFilename)
      }
      else {
        if (file.type === '') {
          devtoolsUiShowNotification({
            message: 'Folders are not supported yet',
            icon: 'carbon:face-dissatisfied',
            classes: 'text-orange',
          })
        }
        newFiles.push(file)
      }
    }
    files.value = [...files.value, ...newFiles]
  }
}

export default async function imports(options: NuxtESLintConfigOptions): Promise<Linter.Config[]> {
  const resolved = resolveOptions(options)

  if (resolved.features.import === false) {
    return []
  }

  const importOptions = resolved.features.import === true
    ? {}
    : resolved.features.import || {}

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const plugin: any = importOptions.package === 'eslint-plugin-import-lite'
    ? (await import('eslint-plugin-import-lite')).default
    : (await import('eslint-plugin-import-x')).default

  return [
    {
      name: 'nuxt/import/rules',
      plugins: {
        import: plugin,
      },
      rules: {
        ...(importOptions.package === 'eslint-plugin-import-lite'
          ? {
              'import/consistent-type-specifier-style': ['error', 'top-level'],
            }
          : {}),
        'import/first': 'error',
        'import/no-duplicates': 'error',
        'import/no-mutable-exports': 'error',
        'import/no-named-default': 'error',

        ...resolved.features.stylistic
          ? {
              'import/newline-after-import': ['error', { count: 1 }],
            }
          : {},
      },
    },
  ]
}

() => {
  return <Plugin>{
    name: 'dev-rendering',
    async transformIndexHtml (html: string, context) {
      const page = context.originalUrl || '/'

      if (page.endsWith('.png')) { return }

      if (page === '/') {
        const templateNames = await fsp.readdir(r('templates'))
        const serializedData = JSON.stringify({ templateNames })
        return html.replace('{{ data }}', serializedData)
      }

      const contents = await fsp.readFile(r(page, 'index.html'), 'utf-8')

      const messages = JSON.parse(await fsp.readFile(r(page, 'messages.json'), 'utf-8'))

      const chunks = contents.split(/\{{2,3}[^{}]+\}{2,3}/)
      let templateString = chunks.shift()
      for (const expression of contents.matchAll(/\{{2,3}([^{}]+)\}{2,3}/g)) {
        const value = runInNewContext(expression[1]!.trim(), {
          version: pkg.version,
          messages: { ...genericMessages, ...messages },
        })
        templateString += `${value}${chunks.shift()}`
      }
      if (chunks.length > 0) {
        templateString += chunks.join('')
      }

      return templateString
    },
  }
}

async function findBestSqliteAdapter(opts: { sqliteConnector?: SQLiteConnector, resolver?: Resolver }) {
  if (process.versions.bun) {
    return opts.resolver ? opts.resolver.resolve('./runtime/internal/connectors/bun-sqlite') : 'db0/connectors/bun-sqlite'
  }

  // if node:sqlite is available, use it
  if (opts.sqliteConnector === 'native' && isNodeSqliteAvailable()) {
    return opts.resolver ? opts.resolver.resolve('./runtime/internal/connectors/node-sqlite') : 'db0/connectors/node-sqlite'
  }

  if (opts.sqliteConnector === 'sqlite3') {
    return 'db0/connectors/sqlite3'
  }

  if (opts.sqliteConnector === 'better-sqlite3') {
    await ensurePackageInstalled('better-sqlite3')

    return 'db0/connectors/better-sqlite3'
  }

  if (isWebContainer()) {
    await ensurePackageInstalled('sqlite3')

    return 'db0/connectors/sqlite3'
  }

  await ensurePackageInstalled('better-sqlite3')

  return 'db0/connectors/better-sqlite3'
}

