function createObservedBody(
  body: ReadableStream<Uint8Array>,
  onDone: () => void | Promise<void>,
  onError: (error: unknown) => void | Promise<void>,
): ReadableStream<Uint8Array> | null {
  if (body.locked) {
    void Promise.resolve(onError(new TypeError('stream is already locked'))).catch((err: unknown) => {
      console.error('[evlog] stream error handling failed:', err)
    })
    return null
  }

  const reader = body.getReader()
  let settled = false

  const settle = (fn: () => void | Promise<void>) => {
    if (settled) return
    settled = true
    void Promise.resolve(fn()).catch((err: unknown) => {
      console.error('[evlog] stream completion handling failed:', err)
    })
  }

  return new ReadableStream<Uint8Array>({
    async pull(controller) {
      try {
        const { done, value } = await reader.read()
        if (done) {
          settle(onDone)
          controller.close()
          return
        }
        controller.enqueue(value)
      } catch (err) {
        settle(() => onError(err))
        controller.error(err)
      }
    },

    async cancel(reason) {
      try {
        await reader.cancel(reason)
      } finally {
        settle(onDone)
      }
    },
  })
}

function buildEvents(): TimedEvent[] {
  const events: TimedEvent[] = []

  events.push({ at: START_AT - 50, run: () => {
    phase.value = 'flowing'
  } })

  stages.forEach((_, i) => {
    events.push({
      at: START_AT + i * STEP_DELAY,
      run: () => {
        stageIdx.value = i
      },
    })
  })

  const fanOutAt = START_AT + stages.length * STEP_DELAY
  events.push({ at: fanOutAt, run: () => {
    phase.value = 'fan-out'
  } })
  events.push({
    at: fanOutAt + FAN_OUT_DELAY,
    run: () => {
      drainHits.value = { ...drainHits.value, main: true }
    },
  })
  events.push({
    at: fanOutAt + FAN_OUT_DELAY + 250,
    run: () => {
      drainHits.value = { ...drainHits.value, signed: true }
    },
  })
  events.push({
    at: fanOutAt + FAN_OUT_DELAY + 500,
    run: () => {
      phase.value = 'done'
    },
  })
  events.push({
    at: fanOutAt + TAIL_HOLD,
    run: () => {
      phase.value = 'hold'
    },
  })

  return events
}

function buildEvents(): TimedEvent[] {
  const events: TimedEvent[] = []

  sourceEvents.forEach((event, i) => {
    const base = ENTER_AT + i * EVENT_INTERVAL

    events.push({
      at: base,
      run: () => {
        activeIdx.value = i
        eventStage.value = eventStage.value.map((s, idx) => idx === i ? 'active' : s)
      },
    })

    events.push({
      at: base + FORK_DELAY,
      run: () => {
        eventStage.value = eventStage.value.map((s, idx) => idx === i ? 'forked' : s)
      },
    })

    events.push({
      at: base + LAND_DELAY,
      run: () => {
        eventStage.value = eventStage.value.map((s, idx) => idx === i ? 'landed' : s)
        mainCount.value++
        if (event.audit) auditCount.value++
        else filteredCount.value++
      },
    })

    events.push({
      at: base + ARCHIVE_DELAY,
      run: () => {
        eventStage.value = eventStage.value.map((s, idx) => idx === i ? 'archived' : s)
      },
    })
  })

  return events
}

function buildEvents(): TimedEvent[] {
  const events: TimedEvent[] = []

  events.push({ at: RACE_AT - 50, run: () => {
    phase.value = 'racing'
  } })

  for (let s = 1; s <= RACE_STEPS; s++) {
    const t = s / RACE_STEPS
    const eased = 1 - Math.pow(1 - t, 3)
    events.push({
      at: RACE_AT + (s / RACE_STEPS) * RACE_DURATION,
      run: () => {
        animatedOps.value = libs.map(l => Math.round(l.ops * eased))
      },
    })
  }

  pinoLines.forEach((_, i) => {
    events.push({
      at: PINO_AT + i * PINO_INTERVAL,
      run: () => {
        linesShown.value = i + 1
      },
    })
  })

  events.push({ at: COLLAPSE_AT, run: () => {
    phase.value = 'collapsing'
    linesCollapsed.value = true
  } })
  events.push({ at: COLLAPSE_AT + 400, run: () => {
    phase.value = 'collapsed'
  } })
  events.push({ at: COLLAPSE_AT + TAIL_HOLD - 200, run: () => {
    phase.value = 'hold'
  } })

  return events
}

(adapter, i) => {
  const flightStart = EMIT_AT + 200 + i * ADAPTER_INTERVAL

  events.push({
    at: flightStart,
    run: () => setState(adapter.id, 'inflight'),
  })

  if (adapter.flaky) {
    events.push({
      at: flightStart + FLAKY_FAIL_AT,
      run: () => {
        setState(adapter.id, 'failing')
        retryCount.value = { ...retryCount.value, [adapter.id]: 1 }
      },
    })
    events.push({
      at: flightStart + FLAKY_BACKOFF_AT,
      run: () => setState(adapter.id, 'backoff'),
    })
    events.push({
      at: flightStart + FLAKY_RETRY_AT,
      run: () => setState(adapter.id, 'retrying'),
    })
    events.push({
      at: flightStart + FLAKY_OK_AT,
      run: () => setState(adapter.id, 'ok'),
    })
    lastResolve = Math.max(lastResolve, flightStart + FLAKY_OK_AT)
  } else {
    events.push({
      at: flightStart + RESOLVE_DELAY,
      run: () => setState(adapter.id, 'ok'),
    })
    lastResolve = Math.max(lastResolve, flightStart + RESOLVE_DELAY)
  }
}

function buildEvents(): TimedEvent[] {
  const events: TimedEvent[] = []

  for (let n = 0; n < EMIT_COUNT; n++) {
    const base = FIRST_EMIT_DELAY_MS + n * CYCLE_MS

    events.push({ at: base, run: () => {
      resetCycle()
      eventSent.value = true
    } })
    events.push({ at: base + EMIT_TO_BUS_MS, run: () => {
      onBus.value = true
      totalEmitted.value = n + 1
    } })
    events.push({ at: base + BUS_TO_INFLIGHT_MS, run: () => {
      state.value = { sync: 'inflight', iter: 'inflight', ring: 'inflight' }
    } })
    events.push({ at: base + SYNC_DELIVERED_MS, run: () => {
      state.value = { ...state.value, sync: 'delivered' }
    } })
    events.push({ at: base + ITER_DELIVERED_MS, run: () => {
      state.value = { ...state.value, iter: 'delivered' }
    } })
    events.push({ at: base + RING_DELIVERED_MS, run: () => {
      state.value = { ...state.value, ring: 'delivered' }
      ringFill.value = Math.min(ringFill.value + 1, RING_MAX)
    } })
    events.push({ at: base + CYCLE_REST_MS, run: () => {
      eventSent.value = false
      onBus.value = false
    } })
  }

  return events
}

function buildEvents(): TimedEvent[] {
  const events: TimedEvent[] = []

  requests.forEach((row, i) => {
    const base = i * ROW_INTERVAL

    events.push({
      at: base + ENTER_AT,
      run: () => {
        rowPhase.value = rowPhase.value.map((p, idx) => idx === i ? 'visible' : p)
      },
    })

    rules.forEach((_, ruleIdx) => {
      events.push({
        at: base + ENTER_AT + 250 + ruleIdx * RULE_INTERVAL,
        run: () => {
          rulesShown.value = rulesShown.value.map((v, idx) => idx === i ? ruleIdx + 1 : v)
        },
      })
    })

    events.push({
      at: base + ENTER_AT + 250 + rules.length * RULE_INTERVAL,
      run: () => {
        rowPhase.value = rowPhase.value.map((p, idx) => idx === i ? 'tail-evaluated' : p)
      },
    })

    const tailMatched = row.matches.some(m => m)
    if (!tailMatched) {
      events.push({
        at: base + HEAD_ROLL_AT,
        run: () => {
          rowPhase.value = rowPhase.value.map((p, idx) => idx === i ? 'head-rolled' : p)
        },
      })
    }

    events.push({
      at: base + RESOLVE_AT,
      run: () => {
        rowPhase.value = rowPhase.value.map((p, idx) => idx === i ? 'resolved' : p)
      },
    })
  })

  return events
}

function buildEvents(): TimedEvent[] {
  const events: TimedEvent[] = []

  events.push({
    at: NARRATE_AT - 50,
    run: () => {
      phase.value = 'narrating'
    },
  })

  lines.forEach((_, i) => {
    events.push({
      at: NARRATE_AT + i * NARRATE_INTERVAL,
      run: () => {
        lineRevealed.value = lineRevealed.value.map((v, idx) => idx === i ? true : v)
      },
    })
  })

  const collapseStart = NARRATE_AT + lines.length * NARRATE_INTERVAL + NARRATE_HOLD

  events.push({
    at: collapseStart - 50,
    run: () => {
      phase.value = 'collapsing'
    },
  })

  lines.forEach((_, i) => {
    events.push({
      at: collapseStart + i * COLLAPSE_INTERVAL,
      run: () => {
        lineCollapsed.value = lineCollapsed.value.map((v, idx) => idx === i ? true : v)
        fieldRevealed.value = fieldRevealed.value.map((v, idx) => idx === i ? true : v)
      },
    })
  })

  const collapseEnd = collapseStart + lines.length * COLLAPSE_INTERVAL + COLLAPSE_HOLD

  events.push({
    at: collapseEnd,
    run: () => {
      phase.value = 'wide'
    },
  })

  return events
}
